use anyhow::Result;
use rutt_core::{Action, FileItem, State};
use slint::{ModelRc, SharedString, VecModel};
use std::rc::Rc;

slint::include_modules!();

#[tokio::main]
async fn main() -> Result<()> {
    let app = AppWindow::new()?;

    // Initial Mock State
    let mut state = State::DirectoryLoaded {
        path: "/mock/path".to_string(),
        items: vec![
            FileItem { name: "Documents".to_string(), is_dir: true, size: 0 },
            FileItem { name: "Downloads".to_string(), is_dir: true, size: 0 },
            FileItem { name: "config.toml".to_string(), is_dir: false, size: 1024 },
            FileItem { name: "notes.txt".to_string(), is_dir: false, size: 512 },
        ],
        selected_index: 0,
    };

    update_ui_from_state(&app, &state);

    let app_weak = app.as_weak();

    app.on_key_pressed(move |key_text: SharedString| {
        let app = app_weak.unwrap();
        let action = match key_text.as_str() {
            "q" => Some(Action::Quit),
            "k" | "\u{1f811}" => Some(Action::MoveUp),   // \u{1f811} = Up Arrow
            "j" | "\u{1f813}" => Some(Action::MoveDown), // \u{1f813} = Down Arrow
            "\n" | "l" | "\u{1f812}" => Some(Action::Enter), // \u{1f812} = Right Arrow
            "\x08" | "h" | "\u{1f810}" => Some(Action::Back), // \x08 = Backspace, \u{1f810} = Left Arrow
            _ => None,
